import React from 'react';
import { Link } from 'react-router-dom';

const Navbar = () => {
  return (
    <nav style={{
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      padding: '15px 50px',
      backgroundColor: '#2c3e50',
      color: 'white',
      boxShadow: '0 2px 5px rgba(0,0,0,0.1)'
    }}>
      <h2 style={{ margin: 0, color: '#ecf0f1' }}>FreelanceHub</h2>
      <ul style={{
        display: 'flex',
        listStyle: 'none',
        gap: '25px',
        margin: 0,
        padding: 0
      }}>
        <li><Link to="/" style={{ color: 'white', textDecoration: 'none', fontWeight: 'bold' }}>Home</Link></li>
        <li><Link to="/post" style={{ color: 'white', textDecoration: 'none', fontWeight: 'bold' }}>Post Project</Link></li>
        <li><Link to="/about" style={{ color: 'white', textDecoration: 'none', fontWeight: 'bold' }}>About</Link></li>
      </ul>
    </nav>
  );
};

export default Navbar;
